            (id, language, scam_type, title, content, key_phrases, times_matched, is_active)
            VALUES (
             '006f3673-6d33-45ee-8889-1be7e6f23dc0', 'hi', 'customs_seizure', 'सीमा शुल्क पार्सल जब्ती घोटाला', 'यह मुंबई एयरपोर्ट सीमा शुल्क विभाग है। मैं अधिकारी Iyer बोल रहा हूं। आपके नाम से बुक पार्सल जब्त हुआ है जिसमें प्रतिबंधित सामान है। एफआईआर से बचने के लिए अभी जुर्माना भरें।',
             '{"पार्सल जब्त","जुर्माना भरें","प्रतिबंधित सामान","एफआईआर से बचें"}', 163, TRUE
            );
